func TestRestructure_ResourceOptionalSection(t *testing.T) {
	input := lines(
		"---",
		`subcategory: "Log Integration"`,
		"---",
		"",
		"# Resource: mongodbatlas_log_integration",
		"",
		"Some description text.",
		"",
		"<!-- schema generated by tfplugindocs -->",
		"## Schema",
		"",
		"### Required",
		"",
		"- `log_types` (Set of String) Array of log types.",
		"- `project_id` (String) Unique ID.",
		"- `type` (String) The type discriminator.",
		"",
		"### Optional",
		"",
		"- `api_key` (String, Sensitive) Required when type is: DATADOG. API key for auth.",
		"- `bucket_name` (String) Required when type is: GCS, S3. Name of the bucket.",
		"- `kms_key` (String) Applicable when type is: S3. AWS KMS key ID.",
		"- `region` (String) Required when type is: DATADOG. Datadog region.",
		"",
		"### Read-Only",
		"",
		"- `integration_id` (String) Unique ID.",
		"",
		"## Import",
		"",
		"Import instructions here.",
		"",
	)

	expected := lines(
		"---",
		`subcategory: "Log Integration"`,
		"---",
		"",
		"# Resource: mongodbatlas_log_integration",
		"",
		"Some description text.",
		"",
		"<!-- schema generated by tfplugindocs -->",
		"## Schema",
		"",
		"### Required",
		"",
		"- `log_types` (Set of String) Array of log types.",
		"- `project_id` (String) Unique ID.",
		"- `type` (String) The type discriminator.",
		"",
		"### Optional",
		"",
		"#### `type` of value `DATADOG`",
		"",
		"- `api_key` (String, Sensitive) **Required.** API key for auth.",
		"- `region` (String) **Required.** Datadog region.",
		"",
		"#### `type` of value `GCS`",
		"",
		"- `bucket_name` (String) **Required.** Name of the bucket.",
		"",
		"#### `type` of value `S3`",
		"",
		"- `bucket_name` (String) **Required.** Name of the bucket.",
		"- `kms_key` (String) AWS KMS key ID.",
		"",
		"### Read-Only",
		"",
		"- `integration_id` (String) Unique ID.",
		"",
		"## Import",
		"",
		"Import instructions here.",
		"",
	)

	result := RestructurePolymorphicDocs(input)
	if result != expected {
		t.Errorf("mismatch.\n\nGot:\n---\n%s\n---\n\nExpected:\n---\n%s\n---", result, expected)
	}
}

