func TestRestructure_Idempotency(t *testing.T) {
	input := lines(
		"<!-- schema generated by tfplugindocs -->",
		"## Schema",
		"",
		"### Optional",
		"",
		"- `api_key` (String, Sensitive) Required when type is: DATADOG. API key.",
		"- `bucket` (String) Required when type is: S3. Bucket name.",
		"",
	)

	first := RestructurePolymorphicDocs(input)
	second := RestructurePolymorphicDocs(first)

	if first != second {
		t.Errorf("not idempotent.\n\nFirst pass:\n---\n%s\n---\n\nSecond pass:\n---\n%s\n---", first, second)
	}
}

